#include <cstdlib>
#include <iostream>
#include <string>
#include <cstring>
#include <fstream>
#include <iomanip>
#include <cmath>
#include <omp.h>

#ifdef PROFILING
#include "timer.h"
#endif

#ifdef TIMING
#include "timing.h"
#endif

// Inline definitions from CLHelper.h, timer.h, and util.h to avoid missing headers
// Removed OpenCL specific dependencies and replaced with OpenMP logic

#define MAX_THREADS_PER_BLOCK 256

struct Node {
    int starting;
    int no_of_edges;
};

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time= 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

// Inline timer class implementation if needed, but simplified for OpenMP translation
// Assuming timer.h is available or inline simplified version
class timer {
    public:
        timer(const char *name = 0) : name(name), write_on_exit(0) { reset(); }
        ~timer() { if (write_on_exit != 0) print(*write_on_exit); }
        void start() { /* OpenMP or gettimeofday based timing */ }
        void stop() { /* OpenMP or gettimeofday based timing */ }
        void reset() { total_time = 0; count = 0; }
        double getTimeInSeconds() { return 0.0; } // Simplified
    private:
        long long total_time;
        unsigned long long count;
        const char *const name;
        std::ostream *const write_on_exit;
        void print(std::ostream &str) { str << name << ": " << total_time << "\n"; }
};

// Inline util functions
#define MAX_RELATIVE_ERROR .002
template<typename datatype>
void compare_results(const datatype *cpu_results, const datatype *gpu_results, const int size){
    char passed = true;
    for (int i=0; i<size; i++){
        if (cpu_results[i] != gpu_results[i]){
            passed = false;
        }
    }
    if (passed){
        std::cout << "--cambine:passed:-)" << std::endl;
    }
    else{
        std::cout << "--cambine: failed:-(" << std::endl;
    }
    return ;
}

void run_bfs_cpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size, \
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask, \
                 char *h_graph_visited, int *h_cost_ref)
{
    char stop;
    int k = 0;
    do {
        stop=false;
        // Parallelize the first loop
        #pragma omp parallel for
        for(int tid = 0; tid < no_of_nodes; tid++ ) {
            if (h_graph_mask[tid] == true) {
                h_graph_mask[tid]=false;
                for(int i=h_graph_nodes[tid].starting; i<(h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting); i++) {
                    int id = h_graph_edges[i];	
                    if(!h_graph_visited[id]) {	
                        h_cost_ref[id]=h_cost_ref[tid]+1;
                        h_updating_graph_mask[id]=true;
                    }
                }
            }
        }

        // Parallelize the second loop
        #pragma omp parallel for
        for(int tid=0; tid< no_of_nodes ; tid++ ) {
            if (h_updating_graph_mask[tid] == true) {
                h_graph_mask[tid]=true;
                h_graph_visited[tid]=true;
                stop=true;
                h_updating_graph_mask[tid]=false;
            }
        }
        k++;
    } while(stop);
}

void run_bfs_gpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size, \
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask, \
                 char *h_graph_visited, int *h_cost)
{
    char h_over;

    // In OpenMP version, we directly operate on host memory
    // No need for device memory allocation

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
    // Simulate init time calculation
    init_time = 0;
#endif

    // No malloc for device, using host pointers directly

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    mem_alloc_time = 0;
#endif

    // No H2D copy needed, data is already in host memory

#ifdef PROFILING
    timer kernel_timer;
    double kernel_time = 0.0;
    kernel_timer.reset();
    kernel_timer.start();
#endif

    do {
        h_over = false;

        // BFS_1 equivalent: Process active nodes
        #pragma omp parallel for
        for(int tid = 0; tid < no_of_nodes; tid++) {
            if(h_graph_mask[tid]) {
                h_graph_mask[tid] = false;
                for(int i = h_graph_nodes[tid].starting; i < (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting); i++) {
                    int id = h_graph_edges[i];
                    if(!h_graph_visited[id]) {
                        h_cost[id] = h_cost[tid] + 1;
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

        // BFS_2 equivalent: Update visited and check if any node was updated
        char local_over = false;
        #pragma omp parallel for
        for(int tid = 0; tid < no_of_nodes; tid++) {
            if(h_updating_graph_mask[tid]) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                h_updating_graph_mask[tid] = false;
                local_over = true;
            }
        }

        if(local_over) h_over = true;

    } while(h_over);

#ifdef PROFILING
    kernel_timer.stop();
    kernel_time = kernel_timer.getTimeInSeconds();
#endif

    // No D2H copy needed, data is already in host memory

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

#ifdef PROFILING
    std::cout<<"kernel time(s):"<<kernel_time<<std::endl;
#endif

    // No free needed for device memory

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    close_time = 0;
    total_time = 0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    return ;
}

void Usage(int argc, char**argv)
{
    fprintf(stderr,"Usage: %s <input_file> [-p platform] [-d device] [-t gpu(0)/cpu(1)]\n", argv[0]);
}

int main(int argc, char * argv[])
{
    int no_of_nodes;
    int edge_list_size;
    FILE *fp;
    Node* h_graph_nodes;
    char *h_graph_mask, *h_updating_graph_mask, *h_graph_visited;

    try {
        char *input_f;
        if(argc < 2) {
            Usage(argc, argv);
            exit(0);
        }

        input_f = argv[1];
        printf("Reading File\n");

        fp = fopen(input_f,"r");
        if(!fp) {
            printf("Error Reading graph file\n");
            return 0;
        }

        int source = 0;

        fscanf(fp,"%d",&no_of_nodes);

        int num_of_blocks = 1;
        int num_of_threads_per_block = no_of_nodes;

        if(no_of_nodes>MAX_THREADS_PER_BLOCK) {
            num_of_blocks = (int)ceil(no_of_nodes/(double)MAX_THREADS_PER_BLOCK);
            num_of_threads_per_block = MAX_THREADS_PER_BLOCK;
        }
        int work_group_size = num_of_threads_per_block;

        h_graph_nodes = (Node*) malloc(sizeof(Node)*no_of_nodes);
        h_graph_mask = (char*) malloc(sizeof(char)*no_of_nodes);
        h_updating_graph_mask = (char*) malloc(sizeof(char)*no_of_nodes);
        h_graph_visited = (char*) malloc(sizeof(char)*no_of_nodes);

        int start, edgeno;

        for(int i = 0; i < no_of_nodes; i++) {
            fscanf(fp,"%d %d",&start,&edgeno);
            h_graph_nodes[i].starting = start;
            h_graph_nodes[i].no_of_edges = edgeno;
            h_graph_mask[i]=false;
            h_updating_graph_mask[i]=false;
            h_graph_visited[i]=false;
        }

        fscanf(fp,"%d",&source);
        source=0;

        h_graph_mask[source]=true;
        h_graph_visited[source]=true;
        fscanf(fp,"%d",&edge_list_size);
        int id,cost;
        int* h_graph_edges = (int*) malloc(sizeof(int)*edge_list_size);
        for(int i=0; i < edge_list_size ; i++) {
            fscanf(fp,"%d",&id);
            fscanf(fp,"%d",&cost);
            h_graph_edges[i] = id;
        }

        if(fp)
            fclose(fp);

        int *h_cost = (int*) malloc(sizeof(int)*no_of_nodes);
        int *h_cost_ref = (int*)malloc(sizeof(int)*no_of_nodes);
        for(int i=0; i<no_of_nodes; i++) {
            h_cost[i]=-1;
            h_cost_ref[i] = -1;
        }
        h_cost[source]=0;
        h_cost_ref[source]=0;

        // Run OpenMP version (translated from GPU)
        run_bfs_gpu(no_of_nodes,h_graph_nodes,edge_list_size,h_graph_edges, h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost);

        // Reset for CPU reference
        for(int i = 0; i < no_of_nodes; i++) {
            h_graph_mask[i]=false;
            h_updating_graph_mask[i]=false;
            h_graph_visited[i]=false;
        }

        source=0;
        h_graph_mask[source]=true;
        h_graph_visited[source]=true;
        run_bfs_cpu(no_of_nodes,h_graph_nodes,edge_list_size,h_graph_edges, h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost_ref);

        compare_results<int>(h_cost_ref, h_cost, no_of_nodes);

        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
        free(h_graph_edges);
        free(h_cost);
        free(h_cost_ref);

    } catch(std::string msg) {
        std::cout<<"--cambine: exception in main ->"<<msg<<std::endl;
        if(h_graph_nodes) free(h_graph_nodes);
        if(h_graph_mask) free(h_graph_mask);
        if(h_updating_graph_mask) free(h_updating_graph_mask);
        if(h_graph_visited) free(h_graph_visited);
    }

    return 0;
}
